// กรองเฉพาะ row ที่ Status = 'pending'
const items = $input.all();

const pending = items.filter(item => {
  const status = (item.json['Status'] || '').toLowerCase().trim();
  return status === 'pending';
});

if (pending.length === 0) {
  console.log('ไม่มีสินค้าที่รอสร้างบทความ');
  return [];
}

console.log(`พบ ${pending.length} สินค้าที่รอสร้างบทความ`);
return pending;

// รวมข้อมูลจาก Google Sheet + Shopee page
const shopeeHtml = $input.first().json.data || '';
const rowData = $('วนทีละสินค้า').first().json;

let shopeeDescription = '';
let autoImage = '';

try {
  const match = shopeeHtml.match(/<script id="__NEXT_DATA__" type="application\/json">(.*?)<\/script>/);
  if (match) {
    const nextData = JSON.parse(match[1]);
    const item = nextData?.props?.pageProps?.initialData?.data?.productItem;
    if (item) {
      shopeeDescription = (item.description || '').substring(0, 800);
      autoImage = item.images?.[0]
        ? `https://down-th.img.susercontent.com/file/${item.images[0]}`
        : '';
    }
  }
} catch (e) {}

// ใช้รูปจาก Sheet ก่อน ถ้าไม่มีค่อย fallback ไป auto-extract
const featuredImage = (rowData['รูปภาพ'] || '').trim() || autoImage || null;

return [{
  json: {
    productName: rowData['ชื่อสินค้า'],
    price: rowData['ราคา'] || '',
    category: rowData['หมวดหมู่'],
    shopeeUrl: rowData['Shopee URL'],
    affiliateUrl: rowData['Affiliate URL'] || rowData['Shopee URL'],
    additionalInfo: rowData['จุดเด่น'] || '',
    shopeeDescription,
    featuredImage,
    row_number: rowData.row_number,
  }
}];

