const aiResponse = $input.first().json;
const productData = $('เตรียมข้อมูล').first().json;

let review;
try {
  const rawContent = aiResponse.message?.content
    || aiResponse.choices?.[0]?.message?.content
    || '';
  const cleaned = rawContent
    .replace(/```json\n?/gi, '')
    .replace(/```\n?/gi, '')
    .trim();
  review = JSON.parse(cleaned);
} catch (e) {
  throw new Error('ไม่สามารถ parse JSON จาก AI ได้: ' + e.message);
}

const slug = (review.slug || productData.productName)
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .substring(0, 80)
  + '-' + Date.now();

const categorySlug = productData.category
  .toLowerCase()
  .replace(/[^a-z0-9ก-๙\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-');

return [{
  json: {
    title: review.title,
    slug,
    excerpt: review.excerpt,
    content: review.content,
    pros: review.pros || [],
    cons: review.cons || [],
    rating: review.rating || 4.0,
    featuredImage: productData.featuredImage || null,
    scoreBreakdown: review.scoreBreakdown || null,
    useCases: review.useCases || [],
    affiliateUrl: productData.affiliateUrl || null,
    price: productData.price || null,
    productName: productData.productName,
    categoryName: productData.category,
    categorySlug,
    published: true,
    row_number: productData.row_number,
  }
}];
